// FlixHQ Movie Online Stream Provider
// Extracts streaming sources from FlixHQ using PoW captcha and AES-256-GCM decryption.

var BASE_URL = "https://flixhq.one";
var UA = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36";

// ─── PoW hash constants ──────────────────────────────────────────────────────
var POW_BLK = 512;
var POW_MASK = POW_BLK - 1;
var POW_ROUNDS = 2;
var P1 = 2654435761;
var P2 = 2246822519;

function rotl(v, n) { return (v << n | v >>> (32 - n)) >>> 0; }
function m32(a, b) { return Math.imul(a, b) >>> 0; }

function qr(s) {
  s[0] = (s[0] + s[1]) >>> 0; s[3] = rotl(s[3] ^ s[0], 16);
  s[2] = (s[2] + s[3]) >>> 0; s[1] = rotl(s[1] ^ s[2], 12);
  s[0] = (s[0] + s[1]) >>> 0; s[3] = rotl(s[3] ^ s[0], 8);
  s[2] = (s[2] + s[3]) >>> 0; s[1] = rotl(s[1] ^ s[2], 7);
}

var POW_ST = [0, 0, 0, 0];
var POW_MEM = new Array(512);
var POW_RES = [0, 0, 0, 0, 0, 0, 0, 0];

function powHash(input, len) {
  POW_ST[0] = 1779033703;
  POW_ST[1] = 3144134277;
  POW_ST[2] = 1013904242;
  POW_ST[3] = 2773480762;

  for (var i = 0; i < len; i++) {
    POW_ST[0] = (POW_ST[0] + input[i]) >>> 0;
    POW_ST[0] = rotl(POW_ST[0], 7);
    qr(POW_ST);
  }
  for (var i = 0; i < 8; i++) qr(POW_ST);

  for (var i = 0; i < POW_BLK; i++) { 
    qr(POW_ST); 
    POW_MEM[i] = (POW_ST[0] ^ POW_ST[2]) >>> 0; 
  }
  for (var r = 0; r < POW_ROUNDS; r++) {
    for (var i = 0; i < POW_BLK; i++) {
      var a = POW_MEM[i] & POW_MASK;
      var v = (POW_MEM[i] + POW_MEM[a]) >>> 0;
      v = rotl(v, 13);
      v = (v ^ m32(POW_MEM[(i + 1) & POW_MASK], P1)) >>> 0;
      POW_MEM[i] = v; 
      POW_ST[0] = (POW_ST[0] ^ v) >>> 0; 
      qr(POW_ST);
    }
  }
  var stride = POW_BLK / 8;
  for (var i = 0; i < 8; i++) {
    qr(POW_ST); 
    var acc = POW_ST[0]; 
    var base = i * stride;
    for (var j = 0; j < stride; j++) {
      var v = POW_MEM[base + j];
      acc = (acc + v) >>> 0; 
      acc = rotl(acc, 5); 
      acc = (acc ^ m32(v, P2)) >>> 0;
    }
    POW_RES[i] = (acc ^ POW_ST[2]) >>> 0;
  }
  return POW_RES;
}

function clzBits(h) {
  var b = 0;
  for (var i = 0; i < h.length; i++) {
    if (h[i] === 0) { b += 32; continue; }
    b += Math.clz32(h[i]); break;
  }
  return b;
}

function solvePoW(nonce, difficulty) {
  if (typeof CryptoJS !== "undefined" && typeof CryptoJS.solvePoW === "function") {
    return CryptoJS.solvePoW(nonce, difficulty);
  }

  if (difficulty <= 0) return "0";

  var pfx = nonce + ":";
  var pfxBytes = new Array(pfx.length);
  for (var i = 0; i < pfx.length; i++) {
    pfxBytes[i] = pfx.charCodeAt(i) & 0xFF;
  }

  var inputBytes = new Array(pfxBytes.length + 10);
  for (var i = 0; i < pfxBytes.length; i++) {
    inputBytes[i] = pfxBytes[i];
  }

  for (var c = 0; c < 10000000; c++) {
    var cStr = String(c);
    var len = pfxBytes.length + cStr.length;
    for (var j = 0; j < cStr.length; j++) {
      inputBytes[pfxBytes.length + j] = cStr.charCodeAt(j) & 0xFF;
    }

    if (clzBits(powHash(inputBytes, len)) >= difficulty) return String(c);
  }
  throw new Error("PoW solver exceeded limit");
}

// ─── Decryption ──────────────────────────────────────────────────────────────
function b64UrlDecode(str) {
  var s = str.replace(/-/g, "+").replace(/_/g, "/");
  var pad = s.length % 4 === 0 ? 0 : 4 - s.length % 4;
  return CryptoJS.enc.Base64.parse(s + "====".substring(0, pad));
}

function selectKeyParts(data) {
  var keyMap = {};
  for (var n = 1; n <= 20; n++) keyMap[String(n)] = [n, 31 - n];
  var parts = Array.isArray(data.key_parts) ? data.key_parts : [];
  var ver = typeof data.version === "string" ? data.version.trim() : "";
  var pair = keyMap[ver];
  if (!pair) return parts;
  var idxA = pair[0], idxB = pair[1];
  if (idxA < 1 || idxB < 1 || idxA > parts.length || idxB > parts.length) return parts;
  var selected = [parts[idxA - 1], parts[idxB - 1]].filter(function(p) {
    return typeof p === "string" && p.length > 0;
  });
  return selected.length > 0 ? selected : parts;
}

function concatParts(parts) {
  var decoded = parts.filter(function(p) { return typeof p === "string" && p.length > 0; }).map(b64UrlDecode);
  var total = 0;
  for (var i = 0; i < decoded.length; i++) total += decoded[i].length;
  var out = new Array(total);
  var off = 0;
  for (var i = 0; i < decoded.length; i++) {
    for (var j = 0; j < decoded[i].length; j++) out[off++] = decoded[i][j];
  }
  return out;
}

function decryptPlayback(data) {
  var key = concatParts(selectKeyParts(data));
  var iv = b64UrlDecode(data.iv);
  var payload = b64UrlDecode(data.payload);
  var decrypted = CryptoJS.AES.decryptGCM(payload, key, iv);
  return JSON.parse(decrypted.toString(CryptoJS.enc.Utf8));
}

// ─── HTTP helpers ────────────────────────────────────────────────────────────
async function fetchText(url, opts) {
  var resp = await fetch(url, Object.assign({ headers: { "User-Agent": UA } }, opts || {}));
  return $toString(resp.body, 0);
}

async function fetchJSON(url, opts) {
  var text = await fetchText(url, opts);
  return JSON.parse(text);
}

function getPath(urlOrPath) {
  var path = urlOrPath || "";
  if (path.indexOf("http") === 0) {
    var m = path.match(/^https?:\/\/[^\/]+(\/.*)/);
    if (m) {
      path = m[1];
    }
  }
  return path.replace(/\/$/, "");
}

// ─── Provider ────────────────────────────────────────────────────────────────
class Provider {

  getSettings() {
    return { episodeServers: ["FlixHQ"] };
  }

  async search(opts) {
    var query = opts.query || opts.media.title;
    var html = await fetchText(BASE_URL + "/search?keyword=" + encodeURIComponent(query));
    var $ = new Doc(html);
    var results = [];
    $.find(".flw-item").each(function(i, el) {
      var a = el.find(".film-name a");
      var href = a.attr("href") || "";
      var title = a.text().trim();
      if (!href || !title) return;
      var path = getPath(href);
      results.push({
        id: path,
        title: title,
        url: BASE_URL + path + "/",
        mediaType: path.indexOf("/watch-series/") !== -1 ? "tv" : "movie",
      });
    });
    return results;
  }

  async findEpisodes(id) {
    var html = await fetchText(BASE_URL + id + "/");
    var $ = new Doc(html);
    var episodes = [];
    $.find(".ss-episodes a").each(function(i, el) {
      var href = el.attr("href") || "";
      var text = el.text().trim();
      var m = href.match(/s(\d+)-e(\d+)/i);
      if (!m) return;
      var season = parseInt(m[1], 10);
      var epNum = parseInt(m[2], 10);
      var path = getPath(href);
      episodes.push({
        id: path,
        number: epNum,
        url: BASE_URL + path + "/",
        title: "S" + season + " E" + epNum + (text ? " - " + text : ""),
      });
    });
    return episodes;
  }

  async findMovieSources(id) {
    return this._extractSources(BASE_URL + id + "/", true);
  }

  async findEpisodeServer(episode, server) {
    var url = episode.url || (BASE_URL + episode.id + "/");
    var results = await this._extractSources(url, false);
    return results && results.length > 0 ? results[0] : null;
  }

  async _extractSources(pageUrl, isMovie) {
    var html = await fetchText(pageUrl);
    var tokenMatch = html.match(/data-token="([^"]+)"/);
    if (!tokenMatch) return [];

    var fd = new FormData();
    fd.set(isMovie ? "players" : "players_show", tokenMatch[1]);
    var servers = await fetchJSON(BASE_URL + "/ajax/ajax.php", {
      method: "POST",
      body: fd,
      headers: {
        "User-Agent": UA,
        "Referer": pageUrl,
        "X-Requested-With": "XMLHttpRequest",
      },
    });

    var results = [];
    for (var i = 0; i < servers.length; i++) {
      if (servers[i].name !== "FlixHQ") continue;
      try {
        var src = await this._extractFromEmbed(servers[i].link, pageUrl);
        if (src) results.push(src);
      } catch (e) {
        console.error("[FlixHQ] Embed extraction failed:", e);
      }
    }
    return results;
  }

  async _extractFromEmbed(embedLink, referer) {
    var parts = embedLink.split("/e/");
    var hostPart = parts[0];
    var rest = parts[1] || "";
    var fileId = rest.split("?")[0];
    var subInfoUrl = "";
    var qIdx = embedLink.indexOf("sub.info=");
    if (qIdx !== -1) subInfoUrl = decodeURIComponent(embedLink.substring(qIdx + 9).split("&")[0]);

    // Step 1: Captcha challenge
    var challenge = await fetchJSON(hostPart + "/api/videos/" + fileId + "/embed/captcha", {
      method: "POST",
      headers: {
        "User-Agent": UA,
        "Referer": embedLink,
        "X-Embed-Origin": BASE_URL,
        "Content-Type": "application/json",
      },
      body: "{}",
    });

    // Step 2: Solve PoW
    console.log("[FlixHQ] Solving PoW. Nonce: " + challenge.pow_nonce + ", Difficulty: " + challenge.pow_difficulty);
    var t0 = Date.now();
    var solution = solvePoW(challenge.pow_nonce, challenge.pow_difficulty);
    console.log("[FlixHQ] Solved PoW in " + (Date.now() - t0) + "ms. Solution: " + solution);

    // Step 3: Verify captcha
    var verifyResult = await fetchJSON(hostPart + "/api/videos/" + fileId + "/embed/captcha/verify", {
      method: "POST",
      headers: {
        "User-Agent": UA,
        "Referer": embedLink,
        "X-Embed-Origin": BASE_URL,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ pow_token: challenge.pow_token, solution: solution }),
    });
    if (verifyResult.status !== "ok" || !verifyResult.token) return null;

    // Step 4: Get encrypted playback data
    var pbData = await fetchJSON(hostPart + "/api/videos/" + fileId + "/embed/playback", {
      method: "POST",
      headers: {
        "User-Agent": UA,
        "Referer": embedLink,
        "X-Embed-Origin": BASE_URL,
        "X-Captcha-Token": verifyResult.token,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ fingerprint: { token: "", viewer_id: "", device_id: "" } }),
    });
    if (!pbData.playback) return null;

    // Step 5: Decrypt
    var decrypted = decryptPlayback(pbData.playback);

    // Step 6: Build subtitles
    var subtitles = [];
    if (subInfoUrl) {
      try {
        var subs = await fetchJSON(subInfoUrl);
        for (var j = 0; j < subs.length; j++) {
          subtitles.push({
            id: subs[j].label || ("sub-" + j),
            url: subs[j].file || "",
            language: subs[j].label || "Unknown",
            isDefault: j === 0,
          });
        }
      } catch (e) { /* subtitle fetch is non-critical */ }
    }

    // Step 7: Build video sources
    var videoSources = [];
    if (decrypted.sources) {
      for (var k = 0; k < decrypted.sources.length; k++) {
        var s = decrypted.sources[k];
        videoSources.push({
          url: s.url,
          type: (s.mime_type && s.mime_type.indexOf("mp4") !== -1) ? "mp4" : "m3u8",
          quality: s.label || "auto",
          subtitles: subtitles,
        });
      }
    }

    return {
      server: "FlixHQ",
      headers: { "Referer": hostPart, "User-Agent": UA },
      videoSources: videoSources,
    };
  }
}
